// === Configuration ===
let SPECIFIC_VALENCE_PREFIXES = [];
let NONSPECIFIC_VALENCE_PREFIXES = [];
let NONSPECIFIC_VALENCE_AFFIXES = [];
let SPECIFIC_VALENCE_PREFIX_SET = new Set();
let NONSPECIFIC_VALENCE_AFFIX_SET = new Set();
let VALENCE_CATEGORY_LABELS = {};
let OBJECT_PREFIXES = [];
let OBJECT_PREFIX_LABELS = new Map();
let OBJECT_PREFIX_GROUPS = [];
let INVALID_COMBINATION_KEYS = new Set();
let TENSE_SUFFIX_RULES = {};
let PRET_UNIVERSAL_CLASS_BY_TENSE = {};
let PRETERITO_CLASS_TENSES = new Set();
let NONSPECIFIC_I_DROP_VERBS = [];
let DIRECTIONAL_PREFIXES = [];
let IA_UA_SUFFIXES = [];
let AN_PREFIX_VOWEL_PREFIXES = [];
let VOWELS = "";
let VOWEL_RE = /[aeiu]/;
let VOWEL_START_RE = /^[aeiu]/;
let VOWEL_END_RE = /[aeiu]$/;
let VALID_VOWEL_SET = new Set();
let VALID_CONSONANTS = new Set();
let DIGRAPHS = [];
let DIGRAPH_SET = new Set();
let SYLLABLE_FORMS = [];
let SYLLABLE_FORM_SET = new Set();
let REDUP_PREFIX_FORMS = new Set();
let COMPOUND_MARKER_RE = /[|~#()\[\]{}\\/?-]/g;
let COMPOUND_MARKER_SPLIT_RE = /[|~#(){}\\/?-]/;
let COMPOUND_ALLOWED_RE = /[|~#()\[\]{}\\/?-]/g;
let PARSE_PIPELINE = [];
let DIRECTIONAL_RULES = [];
let SUPPORTIVE_I_KEEP_SLASH_PREFIXES = new Set();
let SUPPORTIVE_I_KEEP_SLASH_PREFIXES_LOADED = false;
let PATIENTIVO_PERFECTIVO_ALLOWED_FINALS = new Set();
let PATIENTIVO_PERFECTIVO_ALLOWED_FINALS_CLASS_C = new Set();
let PATIENTIVO_PERFECTIVO_ALLOWED_FINALS_CLASS_D = new Set();
const OPTIONAL_SUPPORTIVE_I_MARKER = "(i)";
const OPTIONAL_SUPPORTIVE_Y_MARKER = "(y)";
const OPTIONAL_SUPPORTIVE_I_RE = /\(i\)/g;
const OPTIONAL_SUPPORTIVE_MARKER_RE = /\((i|y)\)/g;
const OPTIONAL_SUPPORTIVE_MARKER_DETECT_RE = /\((i|y)\)/;
const REGEX_OPTIONAL_SUPPORTIVE_I_MARKER = "[i]";
const REGEX_OPTIONAL_SUPPORTIVE_Y_MARKER = "[y]";
const REGEX_OPTIONAL_SUPPORTIVE_MARKER_RE = /\[([iy])\]/gi;
const REGEX_OPTIONAL_SUPPORTIVE_MARKER_DETECT_RE = /\[([iy])\]/i;
const REGEX_ENVELOPE_OBJECT_MARKERS = Object.freeze(["TA", "TE", "MU", "T", "M"]);
const FALLBACK_DIRECTIONAL_PREFIXES = Object.freeze(["wal", "un", "ku"]);
// Supportive marker formats:
// - legacy: editable regex-mode syntax, e.g. (i)/(y)
// - regex: canonical envelope syntax, e.g. [i]/[y]
// - screen: composer mirror syntax, which preserves bracket markers for styling
const SUPPORTIVE_MARKER_FORMAT = Object.freeze({
    legacy: "legacy",
    regex: "regex",
    screen: "screen",
});

function getSupportiveMarkerTokenForLetter(letter = "", format = SUPPORTIVE_MARKER_FORMAT.legacy) {
    const normalized = String(letter || "").trim().toLowerCase();
    const resolvedLetter = normalized === "y" ? "y" : "i";
    if (format === SUPPORTIVE_MARKER_FORMAT.regex || format === SUPPORTIVE_MARKER_FORMAT.screen) {
        return resolvedLetter === "y" ? REGEX_OPTIONAL_SUPPORTIVE_Y_MARKER : REGEX_OPTIONAL_SUPPORTIVE_I_MARKER;
    }
    return resolvedLetter === "y" ? OPTIONAL_SUPPORTIVE_Y_MARKER : OPTIONAL_SUPPORTIVE_I_MARKER;
}

function getSupportiveMarkerLetterFromValue(value = "", format = SUPPORTIVE_MARKER_FORMAT.legacy) {
    const source = String(value || "");
    const match = (
        format === SUPPORTIVE_MARKER_FORMAT.regex || format === SUPPORTIVE_MARKER_FORMAT.screen
    )
        ? source.match(REGEX_OPTIONAL_SUPPORTIVE_MARKER_DETECT_RE)
        : source.match(OPTIONAL_SUPPORTIVE_MARKER_DETECT_RE);
    return match ? String(match[1] || "").toLowerCase() : "";
}

function replaceSupportiveMarkersWithLetters(value = "", format = SUPPORTIVE_MARKER_FORMAT.legacy) {
    const source = String(value || "");
    const pattern = (
        format === SUPPORTIVE_MARKER_FORMAT.regex || format === SUPPORTIVE_MARKER_FORMAT.screen
    )
        ? REGEX_OPTIONAL_SUPPORTIVE_MARKER_RE
        : OPTIONAL_SUPPORTIVE_MARKER_RE;
    return source.replace(pattern, (_match, letter) => String(letter || "").toLowerCase());
}

function getOptionalSupportiveMarkerForLetter(letter = "") {
    return getSupportiveMarkerTokenForLetter(letter, SUPPORTIVE_MARKER_FORMAT.legacy);
}

function getOptionalSupportiveMarkerLetter(value = "") {
    return getSupportiveMarkerLetterFromValue(value, SUPPORTIVE_MARKER_FORMAT.legacy);
}

function hasOptionalSupportiveMarker(value = "") {
    return Boolean(getOptionalSupportiveMarkerLetter(value));
}

function replaceOptionalSupportiveMarkersWithLetters(value = "") {
    return replaceSupportiveMarkersWithLetters(value, SUPPORTIVE_MARKER_FORMAT.legacy);
}

function stripOptionalSupportiveMarkers(value = "") {
    return String(value || "").replace(OPTIONAL_SUPPORTIVE_MARKER_RE, "");
}

function getRegexOptionalSupportiveMarkerForLetter(letter = "") {
    return getSupportiveMarkerTokenForLetter(letter, SUPPORTIVE_MARKER_FORMAT.regex);
}

function getRegexOptionalSupportiveMarkerLetter(value = "") {
    return getSupportiveMarkerLetterFromValue(value, SUPPORTIVE_MARKER_FORMAT.regex);
}

function convertEnvelopeSupportiveMarkersToRegexInput(value = "") {
    return String(value || "").replace(REGEX_OPTIONAL_SUPPORTIVE_MARKER_RE, (_match, letter) => (
        getOptionalSupportiveMarkerForLetter(letter)
    ));
}

function convertRegexInputSupportiveMarkersToEnvelope(value = "") {
    return String(value || "").replace(OPTIONAL_SUPPORTIVE_MARKER_RE, (_match, letter) => (
        getRegexOptionalSupportiveMarkerForLetter(letter)
    ));
}

function replaceLegacyExplicitValenceMarkersWithRegexMarkers(value = "") {
    return String(value || "").replace(
        /(^|[-/])\((ta|te|mu|t|m)\)(?=$|[-/])/gi,
        (_match, separator, token) => `${separator}${String(token || "").toUpperCase()}`
    );
}

function normalizeSupportiveYContextSurface(value = "") {
    return replaceOptionalSupportiveMarkersWithLetters(
        convertEnvelopeSupportiveMarkersToRegexInput(String(value || ""))
    ).replace(/[^a-z]/gi, "").toLowerCase();
}

function getSupportiveYFollowingSurfaceLetters(followingSurface = "") {
    const normalized = normalizeSupportiveYContextSurface(followingSurface);
    if (!normalized) {
        return [];
    }
    const letters = splitVerbLetters(normalized);
    if (letters[0] === "y" && isVerbLetterVowel(letters[1] || "")) {
        return letters.slice(1);
    }
    return letters;
}

function getSupportiveYFollowingVowel(followingSurface = "") {
    const letters = getSupportiveYFollowingSurfaceLetters(followingSurface);
    return letters.find((letter) => isVerbLetterVowel(letter)) || "";
}

function hasInitialReduplicativeSupportiveYPattern(followingSurface = "") {
    const letters = getSupportiveYFollowingSurfaceLetters(followingSurface);
    return (
        letters.length >= 4
        && isVerbLetterVowel(letters[0] || "")
        && letters[1] === "j"
        && letters[2] === "y"
        && isVerbLetterVowel(letters[3] || "")
    );
}

function dropReduplicativeYAfterVj(followingSurface = "") {
    return normalizeSupportiveYContextSurface(followingSurface).replace(/^([aeiu]j)y(?=[aeiu])/i, "$1");
}

function markReduplicativeYAfterVj(
    followingSurface = "",
    format = SUPPORTIVE_MARKER_FORMAT.legacy
) {
    const normalized = normalizeSupportiveYContextSurface(followingSurface);
    if (!normalized) {
        return "";
    }
    const marker = getSupportiveMarkerTokenForLetter("y", format);
    return normalized.replace(/^([aeiu]j)y(?=[aeiu])/i, `$1${marker}`);
}

function markInitialReduplicativeSupportiveYSurface(
    surface = "",
    format = SUPPORTIVE_MARKER_FORMAT.legacy
) {
    const normalized = normalizeSupportiveYContextSurface(surface);
    if (!normalized) {
        return "";
    }
    const leadingMarker = getSupportiveMarkerTokenForLetter("y", format);
    if (!normalized.startsWith("y")) {
        return normalized;
    }
    const remainder = normalized.slice(1);
    return `${leadingMarker}${markReduplicativeYAfterVj(remainder, format) || remainder}`;
}

function resolveOptionalSupportiveYBehavior({
    precedingSurface = "",
    followingSurface = "",
} = {}) {
    const followingVowel = getSupportiveYFollowingVowel(followingSurface);
    const hasReduplicativePattern = hasInitialReduplicativeSupportiveYPattern(followingSurface);
    const normalizedPreceding = normalizeSupportiveYContextSurface(precedingSurface);
    const precedingLetters = splitVerbLetters(normalizedPreceding);
    const finalLetter = precedingLetters.length ? precedingLetters[precedingLetters.length - 1] : "";
    const isWordInitial = !finalLetter;
    if (isWordInitial) {
        return {
            deleteMarker: hasReduplicativePattern,
            deleteReduplicativeY: hasReduplicativePattern,
        };
    }
    if (isVerbLetterConsonant(finalLetter)) {
        return { deleteMarker: true, deleteReduplicativeY: hasReduplicativePattern };
    }
    if (finalLetter === "i") {
        return { deleteMarker: true, deleteReduplicativeY: hasReduplicativePattern };
    }
    if (followingVowel === "e") {
        return { deleteMarker: true, deleteReduplicativeY: hasReduplicativePattern };
    }
    return { deleteMarker: false, deleteReduplicativeY: false };
}

function normalizeSupportiveMarkedLegacySurface(
    value = "",
    format = SUPPORTIVE_MARKER_FORMAT.legacy
) {
    const source = String(value || "");
    if (format === SUPPORTIVE_MARKER_FORMAT.regex || format === SUPPORTIVE_MARKER_FORMAT.screen) {
        return convertEnvelopeSupportiveMarkersToRegexInput(source);
    }
    return source;
}

function formatResolvedSupportiveMarkedSurface(
    value = "",
    format = SUPPORTIVE_MARKER_FORMAT.legacy,
    preserveMarkers = false
) {
    const legacyValue = String(value || "");
    if (!preserveMarkers) {
        return replaceOptionalSupportiveMarkersWithLetters(legacyValue);
    }
    if (format === SUPPORTIVE_MARKER_FORMAT.regex || format === SUPPORTIVE_MARKER_FORMAT.screen) {
        return convertRegexInputSupportiveMarkersToEnvelope(legacyValue);
    }
    return legacyValue;
}

function resolveOptionalSupportiveMarkedSurface({
    precedingSurface = "",
    markedSurface = "",
    inputFormat = SUPPORTIVE_MARKER_FORMAT.legacy,
    outputFormat = inputFormat,
    preserveMarkers = false,
} = {}) {
    const legacyMarkedSurface = normalizeSupportiveMarkedLegacySurface(markedSurface, inputFormat);
    if (!legacyMarkedSurface) {
        return {
            markerLetter: "",
            legacyMarkedSurface: "",
            plainSurface: "",
            outputSurface: "",
        };
    }
    const markerMatch = legacyMarkedSurface.match(OPTIONAL_SUPPORTIVE_MARKER_DETECT_RE);
    const markerLetter = markerMatch ? String(markerMatch[1] || "").toLowerCase() : "";
    let resolvedLegacySurface = legacyMarkedSurface;
    if (markerLetter === "y" && markerMatch) {
        const markerToken = markerMatch[0];
        const markerIndex = legacyMarkedSurface.indexOf(markerToken);
        const localPrecedingSurface = `${String(precedingSurface || "")}${legacyMarkedSurface.slice(0, markerIndex)}`;
        const followingSurface = legacyMarkedSurface.slice(markerIndex + markerToken.length);
        const yBehavior = resolveOptionalSupportiveYBehavior({
            precedingSurface: localPrecedingSurface,
            followingSurface,
        });
        const resolvedFollowingSurface = yBehavior.deleteReduplicativeY
            ? dropReduplicativeYAfterVj(followingSurface)
            : followingSurface;
        resolvedLegacySurface = (
            preserveMarkers && yBehavior.deleteReduplicativeY
                ? legacyMarkedSurface
                : (
                    `${legacyMarkedSurface.slice(0, markerIndex)}`
                    + `${yBehavior.deleteMarker ? "" : markerToken}`
                    + `${resolvedFollowingSurface}`
                )
        );
    }
    return {
        markerLetter,
        legacyMarkedSurface: resolvedLegacySurface,
        plainSurface: replaceOptionalSupportiveMarkersWithLetters(resolvedLegacySurface),
        outputSurface: formatResolvedSupportiveMarkedSurface(
            resolvedLegacySurface,
            outputFormat,
            preserveMarkers
        ),
    };
}

function markOptionalSupportiveSurface(
    value = "",
    letter = "",
    format = SUPPORTIVE_MARKER_FORMAT.legacy
) {
    const normalizedSurface = normalizeSupportiveYContextSurface(value);
    if (!normalizedSurface) {
        return "";
    }
    const supportiveLetter = resolveOptionalSupportiveLetter(letter, normalizedSurface);
    if (supportiveLetter === "y") {
        const supportiveYIndex = normalizedSurface.search(/y(?=[aeiu])/i);
        if (supportiveYIndex < 0) {
            return normalizedSurface;
        }
        const prefix = normalizedSurface.slice(0, supportiveYIndex);
        const ySegment = normalizedSurface.slice(supportiveYIndex);
        if (hasInitialReduplicativeSupportiveYPattern(ySegment)) {
            return `${prefix}${markInitialReduplicativeSupportiveYSurface(ySegment, format)}`;
        }
        if (ySegment.startsWith("y")) {
            return `${prefix}${getSupportiveMarkerTokenForLetter("y", format)}${ySegment.slice(1)}`;
        }
        return normalizedSurface;
    }
    if (normalizedSurface.startsWith("i")) {
        return `${getSupportiveMarkerTokenForLetter("i", format)}${normalizedSurface.slice(1)}`;
    }
    return normalizedSurface;
}

function resolveOptionalSupportiveOutputVerb({
    subjectPrefix = "",
    possessivePrefix = "",
    objectPrefix = "",
    verb = "",
    hasOptionalSupportiveI = false,
    optionalSupportiveLetter = "",
}) {
    if (!hasOptionalSupportiveI || optionalSupportiveLetter !== "y") {
        return String(verb || "");
    }
    const baseVerb = String(verb || "");
    const markedVerb = markOptionalSupportiveSurface(
        baseVerb,
        optionalSupportiveLetter,
        SUPPORTIVE_MARKER_FORMAT.legacy
    );
    if (!hasOptionalSupportiveMarker(markedVerb)) {
        return baseVerb;
    }
    const precedingSurface = `${subjectPrefix || ""}${possessivePrefix || ""}${objectPrefix || ""}`;
    return resolveOptionalSupportiveMarkedSurface({
        precedingSurface,
        markedSurface: markedVerb,
        inputFormat: SUPPORTIVE_MARKER_FORMAT.legacy,
        outputFormat: SUPPORTIVE_MARKER_FORMAT.legacy,
        preserveMarkers: false,
    }).plainSurface || baseVerb;
}

function resolveOptionalSupportiveOutputText({
    value = "",
    hasOptionalSupportiveI = false,
    optionalSupportiveLetter = "",
} = {}) {
    return String(value || "")
        .split(" / ")
        .map((entry) => {
            const form = String(entry || "").trim();
            if (!form) {
                return "";
            }
            return resolveOptionalSupportiveOutputVerb({
                verb: form,
                hasOptionalSupportiveI,
                optionalSupportiveLetter,
            }) || form;
        })
        .filter(Boolean)
        .join(" / ");
}

function buildOutputPrefixedChain({
    subjectPrefix = "",
    possessivePrefix = "",
    objectPrefix = "",
    verb = "",
    hasOptionalSupportiveI = false,
    optionalSupportiveLetter = "",
}) {
    const surfaceVerb = resolveOptionalSupportiveOutputVerb({
        subjectPrefix,
        possessivePrefix,
        objectPrefix,
        verb,
        hasOptionalSupportiveI,
        optionalSupportiveLetter,
    });
    return buildPrefixedChain({
        subjectPrefix,
        possessivePrefix,
        objectPrefix,
        verb: surfaceVerb,
    });
}

function normalizeRegexCoreTokenCase(value = "", options = {}) {
    const forceUppercaseMarkers = options.forceUppercaseMarkers === true;
    return String(value || "")
        .split(/([/-])/)
        .map((part) => {
            if (part === "/" || part === "-") {
                return part;
            }
            const trimmed = String(part || "").trim();
            if (!trimmed) {
                return "";
            }
            if (/^\[[a-z]+\]$/i.test(trimmed)) {
                return `[${trimmed.slice(1, -1).toLowerCase()}]`;
            }
            const supportiveMatch = trimmed.match(/^\[([iy])\]/i);
            if (supportiveMatch) {
                const supportiveLetter = String(supportiveMatch[1] || "").toLowerCase();
                const remainder = trimmed.slice(supportiveMatch[0].length).toLowerCase();
                return `${getRegexOptionalSupportiveMarkerForLetter(supportiveLetter)}${remainder}`;
            }
            const normalized = trimmed.toLowerCase();
            const shouldUppercaseMarker = (
                REGEX_ENVELOPE_OBJECT_MARKERS.includes(trimmed.toUpperCase())
                && (forceUppercaseMarkers || trimmed === trimmed.toUpperCase())
            );
            return shouldUppercaseMarker ? trimmed.toUpperCase() : normalized;
        })
        .join("");
}

function parseComposerPlaceholderLegacyBase(rawValue = "") {
    const raw = String(rawValue || "").trim();
    if (!raw) {
        return null;
    }
    const match = raw.match(/^(--|-)?(_+(?:[a-z]+)?)$/i);
    if (!match) {
        return null;
    }
    const dashPrefix = match[1] === "--"
        ? "--"
        : (match[1] === "-" ? "-" : "");
    const coreText = String(match[2] || "").toLowerCase();
    if (!coreText) {
        return null;
    }
    return {
        dashPrefix,
        coreText,
        displayCore: coreText,
        displayVerb: buildRegexDisplayVerb(dashPrefix, coreText),
    };
}

function serializeComposerPlaceholderValenceScreen(rawValue = "") {
    const raw = String(rawValue || "").trim();
    if (!raw) {
        return "";
    }
    const directMatch = raw.match(/^(--|-)?\((tajta|tejte|mujmu)\)-(_+(?:[a-z]+)?)$/i);
    if (directMatch) {
        const dashPrefix = directMatch[1] === "--"
            ? "--"
            : (directMatch[1] === "-" ? "-" : "");
        const token = String(directMatch[2] || "").toLowerCase();
        const placeholderStem = String(directMatch[3] || "").toLowerCase();
        return `${dashPrefix}(${token})-${placeholderStem}`;
    }
    const wrappedMatch = raw.match(/^(--|-)?\(\((tajta|tejte|mujmu)\)-(_+(?:[a-z]+)?)\)$/i);
    if (wrappedMatch) {
        const dashPrefix = wrappedMatch[1] === "--"
            ? "--"
            : (wrappedMatch[1] === "-" ? "-" : "");
        const token = String(wrappedMatch[2] || "").toLowerCase();
        const placeholderStem = String(wrappedMatch[3] || "").toLowerCase();
        return `${dashPrefix}(${token})-${placeholderStem}`;
    }
    return "";
}

function convertRegexCoreUppercaseMarkersToLegacyExplicitMarkers(value = "") {
    return String(value || "").replace(
        /(^|[-/])((?:TA|TE|MU|T|M))(?=$|[-/])/g,
        (_match, separator, token) => `${separator}(${String(token || "").toLowerCase()})`
    );
}

function getRegexCoreMainObjectCount(coreText = "") {
    const normalized = String(coreText || "").trim();
    if (!normalized) {
        return 0;
    }
    const splitIndex = normalized.lastIndexOf("-");
    if (splitIndex <= 0 || splitIndex >= normalized.length - 1) {
        return 0;
    }
    const head = normalized.slice(0, splitIndex).trim();
    const tail = normalized.slice(splitIndex + 1).trim();
    return head && tail ? 1 : 0;
}

function buildRegexDisplayVerb(dashPrefix = "", coreText = "", options = {}) {
    const normalizedDashPrefix = String(dashPrefix || "").startsWith("--")
        ? "--"
        : (String(dashPrefix || "").startsWith("-") ? "-" : "");
    const normalizedCore = normalizeRegexCoreTokenCase(coreText, options);
    if (!normalizedCore) {
        return normalizedDashPrefix;
    }
    return `${normalizedDashPrefix}(${normalizedCore})`;
}

function parseRegexCore(coreText = "", options = {}) {
    const rawCore = String(coreText || "").trim();
    if (!rawCore) {
        return {
            rawCore,
            coreText: "",
            displayCore: "",
            coreObjectCount: 0,
            isValid: false,
            invalidReason: options.allowEmpty === true ? "" : "core-empty",
        };
    }
    const withoutRegexMarkers = rawCore.replace(REGEX_OPTIONAL_SUPPORTIVE_MARKER_RE, "");
    if (/[()]/.test(rawCore)) {
        return {
            rawCore,
            coreText: rawCore,
            displayCore: "",
            coreObjectCount: 0,
            isValid: false,
            invalidReason: "legacy-parentheses",
        };
    }
    if (/[{}]/.test(withoutRegexMarkers)) {
        return {
            rawCore,
            coreText: rawCore,
            displayCore: "",
            coreObjectCount: 0,
            isValid: false,
            invalidReason: "supportive-marker",
        };
    }
    const displayCore = normalizeRegexCoreTokenCase(rawCore);
    return {
        rawCore,
        coreText: displayCore,
        displayCore,
        coreObjectCount: getRegexCoreMainObjectCount(displayCore),
        isValid: true,
        invalidReason: "",
    };
}

function serializeRegexEnvelope({ dashPrefix = "", coreText = "" } = {}) {
    return buildRegexDisplayVerb(dashPrefix, coreText);
}

function serializeRegexCore(coreState = {}) {
    if (typeof coreState === "string") {
        return normalizeRegexCoreTokenCase(coreState);
    }
    if (coreState && typeof coreState === "object") {
        if (typeof coreState.coreText === "string" && coreState.coreText) {
            return normalizeRegexCoreTokenCase(coreState.coreText);
        }
        if (typeof coreState.displayCore === "string" && coreState.displayCore) {
            return normalizeRegexCoreTokenCase(coreState.displayCore);
        }
        if (typeof coreState.legacyBase === "string" && coreState.legacyBase) {
            return convertLegacyBaseToRegexEnvelopeParts(coreState.legacyBase, coreState).displayCore;
        }
    }
    return "";
}

function convertLegacyBaseToRegexEnvelopeParts(legacyBase = "", options = {}) {
    const raw = String(legacyBase || "").trim();
    let index = 0;
    let dashPrefix = "";
    while (raw[index] === "-" && dashPrefix.length < 2) {
        dashPrefix += "-";
        index += 1;
    }
    const overrideDashPrefix = Object.prototype.hasOwnProperty.call(options, "dashPrefix")
        ? String(options.dashPrefix || "")
        : null;
    const normalizedDashPrefix = overrideDashPrefix === null
        ? dashPrefix
        : (
            overrideDashPrefix.startsWith("--")
                ? "--"
                : (overrideDashPrefix.startsWith("-") ? "-" : "")
        );
    const coreSource = raw.slice(index);
    const displayCore = normalizeRegexCoreTokenCase(
        replaceLegacyExplicitValenceMarkersWithRegexMarkers(
            convertRegexInputSupportiveMarkersToEnvelope(coreSource)
        ),
        { forceUppercaseMarkers: true }
    );
    return {
        dashPrefix: normalizedDashPrefix,
        coreText: displayCore,
        displayCore,
        displayVerb: serializeRegexEnvelope({
            dashPrefix: normalizedDashPrefix,
            coreText: displayCore,
        }),
        coreObjectCount: getRegexCoreMainObjectCount(displayCore),
    };
}

function isAllowedPartialRegexEnvelopeValue(rawValue = "") {
    const trimmed = String(rawValue || "").trim();
    if (!trimmed) {
        return true;
    }
    if (trimmed.includes("?")) {
        return false;
    }
    let index = 0;
    while (trimmed[index] === "-" && index < 2) {
        index += 1;
    }
    if (trimmed[index] === "-") {
        return false;
    }
    const body = trimmed.slice(index);
    if (!body) {
        return true;
    }
    if (!body.startsWith("(")) {
        return false;
    }
    const partialCore = body.slice(1);
    if (!partialCore) {
        return true;
    }
    if (partialCore.includes(")")) {
        return parseRegexEnvelope(trimmed, { allowEmpty: true }).isValid;
    }
    const withoutRegexMarkers = partialCore.replace(REGEX_OPTIONAL_SUPPORTIVE_MARKER_RE, "");
    return !(/[()]/.test(partialCore) || /[{}]/.test(withoutRegexMarkers));
}

function parseRegexEnvelope(rawValue = "", options = {}) {
    const raw = String(rawValue || "");
    const trimmed = raw.trim();
    if (!trimmed) {
        return {
            raw,
            trimmed,
            dashPrefix: "",
            coreText: "",
            displayCore: "",
            displayVerb: "",
            coreObjectCount: 0,
            hasExternalObjectDash: false,
            isValid: false,
            invalidReason: options.allowEmpty === true ? "" : "empty",
        };
    }
    if (trimmed.includes("?")) {
        return {
            raw,
            trimmed,
            dashPrefix: "",
            coreText: "",
            displayCore: "",
            displayVerb: "",
            coreObjectCount: 0,
            hasExternalObjectDash: false,
            isValid: false,
            invalidReason: "search",
        };
    }
    let index = 0;
    let dashPrefix = "";
    while (trimmed[index] === "-" && dashPrefix.length < 2) {
        dashPrefix += "-";
        index += 1;
    }
    if (trimmed[index] === "-") {
        return {
            raw,
            trimmed,
            dashPrefix,
            coreText: "",
            displayCore: "",
            displayVerb: "",
            coreObjectCount: 0,
            hasExternalObjectDash: false,
            isValid: false,
            invalidReason: "dash",
        };
    }
    const body = trimmed.slice(index);
    if (!body.startsWith("(")) {
        return {
            raw,
            trimmed,
            dashPrefix,
            coreText: "",
            displayCore: "",
            displayVerb: "",
            coreObjectCount: 0,
            hasExternalObjectDash: false,
            isValid: false,
            invalidReason: "core-envelope",
        };
    }
    let depth = 0;
    let endIndex = -1;
    for (let i = 0; i < body.length; i += 1) {
        const char = body[i];
        if (char === "(") {
            depth += 1;
        } else if (char === ")") {
            depth -= 1;
            if (depth === 0) {
                endIndex = i;
                break;
            }
            if (depth < 0) {
                break;
            }
        }
    }
    if (endIndex < 0 || depth !== 0 || body.slice(endIndex + 1).trim()) {
        return {
            raw,
            trimmed,
            dashPrefix,
            coreText: "",
            displayCore: "",
            displayVerb: "",
            coreObjectCount: 0,
            hasExternalObjectDash: false,
            isValid: false,
            invalidReason: "core-envelope",
        };
    }
    const parsedCore = parseRegexCore(body.slice(1, endIndex).trim(), options);
    if (!parsedCore.isValid) {
        return {
            raw,
            trimmed,
            dashPrefix,
            coreText: parsedCore.coreText || "",
            displayCore: parsedCore.displayCore || "",
            displayVerb: "",
            coreObjectCount: 0,
            hasExternalObjectDash: false,
            isValid: false,
            invalidReason: parsedCore.invalidReason || "core-envelope",
        };
    }
    return {
        raw,
        trimmed,
        dashPrefix,
        coreText: parsedCore.coreText,
        displayCore: parsedCore.displayCore,
        displayVerb: serializeRegexEnvelope({
            dashPrefix,
            coreText: parsedCore.displayCore,
        }),
        coreObjectCount: parsedCore.coreObjectCount,
        hasExternalObjectDash: Boolean(dashPrefix),
        isValid: true,
        invalidReason: "",
    };
}

function translateRegexCoreToLegacyBase(coreText = "", options = {}) {
    const normalizedDashPrefix = String(options.dashPrefix || "").startsWith("--")
        ? "--"
        : (String(options.dashPrefix || "").startsWith("-") ? "-" : "");
    const displayCore = normalizeRegexCoreTokenCase(coreText);
    const legacyCore = convertRegexCoreUppercaseMarkersToLegacyExplicitMarkers(
        convertEnvelopeSupportiveMarkersToRegexInput(displayCore)
    ).toLowerCase();
    return {
        legacyBase: `${normalizedDashPrefix}${legacyCore}`,
        displayCore,
        displayVerb: buildRegexDisplayVerb(normalizedDashPrefix, displayCore),
        coreObjectCount: getRegexCoreMainObjectCount(displayCore),
        dashPrefix: normalizedDashPrefix,
        effectiveDashPrefix: normalizedDashPrefix,
    };
}

function getStemLeadingSupportiveLetter(stem = "") {
    const normalized = normalizeComposerStem(stem);
    if (!normalized) {
        return "";
    }
    if (normalized.startsWith("i")) {
        return "i";
    }
    if (normalized.startsWith("y")) {
        return "y";
    }
    return "";
}

function resolveOptionalSupportiveLetter(letter = "", analysisVerb = "") {
    const explicit = String(letter || "").trim().toLowerCase();
    if (explicit === "i" || explicit === "y") {
        return explicit;
    }
    const fromAnalysis = getStemLeadingSupportiveLetter(analysisVerb);
    if (fromAnalysis) {
        return fromAnalysis;
    }
    return "i";
}

function getDirectionalPrefixesSource() {
    if (Array.isArray(DIRECTIONAL_PREFIXES) && DIRECTIONAL_PREFIXES.length) {
        return DIRECTIONAL_PREFIXES;
    }
    return FALLBACK_DIRECTIONAL_PREFIXES;
}

function isDirectionalPrefixToken(value = "") {
    const token = String(value || "");
    if (!token) {
        return false;
    }
    return getDirectionalPrefixesSource().includes(token);
}

function getBracketDirectionalPrefixToken(value = "") {
    const token = String(value || "").trim().toLowerCase();
    const match = token.match(/^\[([a-z]+)\]$/);
    if (!match) {
        return "";
    }
    const directional = match[1];
    return isDirectionalPrefixToken(directional) ? directional : "";
}
